   838 |     bool IsStrictLessThanImplied =
   839 |         !StrictLessThan.empty() && CS.isConditionImplied(StrictLessThan);
   840 | 
   841 |     // In order to check that `%a != %b` is true (non-equality), either
   842 |     // condition `%a > %b` or `%a < %b` must hold true. When checking for
   843 |     // non-equality (`IsNe` is true), we return true if one of the two holds,
   844 |     // false in the other cases.
   845 |     if (IsNegatedImplied || IsStrictLessThanImplied)
   846 |       return IsNe;
   847 | 
